import { NavigateOptions, To, useLocation, useNavigate } from 'react-router-dom';
import { useTabs } from '../infra/tabs/hooks/useTabs';
import { useCallback, useEffect } from 'react';
import { TabEventClient } from '../infra/tabs/CachedTabs';

export interface TabNavigateOptions extends NavigateOptions {
    refresh?: boolean;
    forceRefresh?: boolean;
}

export interface TabNavigateFunction {
    (to: To, options?: TabNavigateOptions): void;
    (delta: number): void;
}

/**
 * 根据location pathname 生成唯一的key
 * @param pathname 
 */
const getPathnameKey = (pathname: string) => {
    if (pathname?.endsWith('/')) {
        return pathname.slice(0, -1)?.toLowerCase()?.trim();
    }
    return pathname?.toLowerCase()?.trim();
}


export const useTabNavigate: () => TabNavigateFunction = () => {
    const navigate = useNavigate();
    const location = useLocation();

    const { closeByPathname } = useTabs();

    const customNavigate = useCallback((to: To | number, options: TabNavigateOptions = {}) => {
        if (typeof to === 'number') {
            navigate(to);
        } else {
            if (options.replace) {
                // replace 操作会关闭Tab
                closeByPathname(location.pathname, false);
            }
            try {
                const pathname = typeof to === 'string' ? new URL(to, window.location.origin).pathname : to.pathname as string;
                const targetKey = getPathnameKey(pathname);
                if (options.refresh) {
                    TabEventClient.eventBus.emit(targetKey);
                }

                if (options.forceRefresh) {
                    TabEventClient.refresh(TabEventClient.getKeyByPath(pathname) as string, true);
                }

                navigate(to, options);
            } catch (e) {
                console.error(e);
            }
        }
    }, []);

    return customNavigate;
};

export const useTabListen = (callback: (data: any) => void) => {
    const location = useLocation();

    useEffect(() => {
        TabEventClient?.eventBus?.on(getPathnameKey(location.pathname), callback);

        return () => {
            TabEventClient?.eventBus?.off(getPathnameKey(location.pathname), callback);
        };
    }, []);
};
